// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.atomic.AtomicInteger;

import org.junit.jupiter.api.Test;

class LmdbQueryMemoryManagerTest {

	@Test
	void reservationsAreAccountedPerQueryAndReleasedOnCursorClose() {
		LmdbQueryMemoryManager manager = new LmdbQueryMemoryManager(1_024L, 512L);

		try (LmdbQueryMemoryManager.QueryLedger query = manager.openQuery()) {
			LmdbQueryMemoryManager.Reservation first = query.reserve(192L, null);
			LmdbQueryMemoryManager.Reservation second = query.reserve(128L, null);

			assertThat(first).isNotNull();
			assertThat(second).isNotNull();
			assertThat(query.usedBytes()).isEqualTo(320L);
			assertThat(manager.usedBytes()).isEqualTo(320L);
			assertThat(manager.peakUsedBytes()).isEqualTo(320L);
		}

		assertThat(manager.usedBytes()).isZero();
	}

	@Test
	void refusalIsImmediateWhenNeitherLimitCanBeReclaimed() {
		LmdbQueryMemoryManager manager = new LmdbQueryMemoryManager(384L, 256L);

		try (LmdbQueryMemoryManager.QueryLedger firstQuery = manager.openQuery();
				LmdbQueryMemoryManager.QueryLedger secondQuery = manager.openQuery()) {
			LmdbQueryMemoryManager.Reservation first = firstQuery.reserve(256L, null);
			assertThat(first).isNotNull();

			assertThat(firstQuery.reserve(1L, null)).isNull();
			assertThat(secondQuery.reserve(129L, null)).isNull();
			assertThat(secondQuery.reserve(128L, null)).isNotNull();
			assertThat(manager.usedBytes()).isEqualTo(384L);
		}
	}

	@Test
	void growthAndPartialReleaseUpdateBothLedgers() {
		LmdbQueryMemoryManager manager = new LmdbQueryMemoryManager(512L, 384L);

		try (LmdbQueryMemoryManager.QueryLedger query = manager.openQuery();
				LmdbQueryMemoryManager.Reservation reservation = query.reserve(128L, null)) {
			assertThat(reservation.tryGrow(128L)).isTrue();
			assertThat(reservation.bytes()).isEqualTo(256L);

			reservation.release(96L);

			assertThat(reservation.bytes()).isEqualTo(160L);
			assertThat(query.usedBytes()).isEqualTo(160L);
			assertThat(manager.usedBytes()).isEqualTo(160L);
		}
	}

	@Test
	void pressureReclaimsLeastRecentlyUsedReservationAndPrefersSpill() {
		LmdbQueryMemoryManager manager = new LmdbQueryMemoryManager(256L, 256L);
		List<String> actions = new ArrayList<>();

		try (LmdbQueryMemoryManager.QueryLedger query = manager.openQuery()) {
			LmdbQueryMemoryManager.Reservation oldest = query.reserve(128L,
					new RecordingReclaimable("oldest", actions, true, true));
			LmdbQueryMemoryManager.Reservation newest = query.reserve(128L,
					new RecordingReclaimable("newest", actions, true, true));
			assertThat(oldest).isNotNull();
			assertThat(newest).isNotNull();

			LmdbQueryMemoryManager.Reservation replacement = query.reserve(128L, null);

			assertThat(replacement).isNotNull();
			assertThat(actions).containsExactly("oldest:spill");
			assertThat(oldest.bytes()).isZero();
			assertThat(newest.bytes()).isEqualTo(128L);
			assertThat(query.usedBytes()).isEqualTo(256L);
		}
	}

	@Test
	void failedSpillFallsBackToShed() {
		LmdbQueryMemoryManager manager = new LmdbQueryMemoryManager(128L, 128L);
		List<String> actions = new ArrayList<>();

		try (LmdbQueryMemoryManager.QueryLedger query = manager.openQuery()) {
			assertThat(query.reserve(128L, new RecordingReclaimable("entry", actions, false, true)))
					.isNotNull();

			assertThat(query.reserve(128L, null)).isNotNull();
			assertThat(actions).containsExactly("entry:spill", "entry:shed");
		}
	}

	@Test
	void concurrentQueriesNeverExceedTheGlobalCeiling() throws Exception {
		LmdbQueryMemoryManager manager = new LmdbQueryMemoryManager(512L, 256L);
		ExecutorService workers = Executors.newFixedThreadPool(8);
		CountDownLatch start = new CountDownLatch(1);
		AtomicInteger completed = new AtomicInteger();
		List<Future<?>> futures = new ArrayList<>();

		try {
			for (int worker = 0; worker < 8; worker++) {
				futures.add(workers.submit(() -> {
					start.await();
					try (LmdbQueryMemoryManager.QueryLedger query = manager.openQuery()) {
						for (int attempt = 0; attempt < 1_000; attempt++) {
							try (LmdbQueryMemoryManager.Reservation reservation = query.reserve(64L, null)) {
								if (reservation != null) {
									reservation.tryGrow(64L);
									assertThat(reservation.bytes()).isBetween(64L, 128L);
								}
							}
						}
					}
					completed.incrementAndGet();
					return null;
				}));
			}

			start.countDown();
			for (Future<?> future : futures) {
				future.get();
			}
		} finally {
			workers.shutdownNow();
		}

		assertThat(completed).hasValue(8);
		assertThat(manager.peakUsedBytes()).isLessThanOrEqualTo(manager.maxBytes());
		assertThat(manager.usedBytes()).isZero();
	}

	private record RecordingReclaimable(String name, List<String> actions, boolean spillResult,
			boolean shedResult) implements LmdbQueryMemoryManager.Reclaimable {

		@Override
		public boolean spill() {
			actions.add(name + ":spill");
			return spillResult;
		}

		@Override
		public boolean shed() {
			actions.add(name + ":shed");
			return shedResult;
		}
	}
}
